      "noiDung": "TÊN HUYỆT\nHuyệt ở xương (Cốt) mu, có hình dạng cong (khúc), vì vậy gọi là Khúc Cốt.\nTÊN KHÁC\nHồi Cốt, Khuất Cốt, Niệu Bao.\nXUẤT XỨ\nGiáp Ất Kinh.\nVỊ TRÍ\nỞ trên xương mu, dưới huyệt Trung Cực 1 thốn hoặc chỗ lõm ngay chính giữa bờ trên xương mu.\nĐẶC TÍNH\nHuyệt thứ 2 của mạch Nhâm.\nHuyệt Hội của mạch Nhâm và kinh Túc Quyết Âm Can.\nHuyệt Hội của kinh Túc Quyết Âm Can và mạch Âm Kiều.\nHuyệt Hội của các kinh cân – cơ của 3 kinh âm ở chân.\nCHỦ TRỊ\nTrị bàng quang viêm, dịch hoàn viêm, tử cung sa, kinh nguyệt không đều, tiểu khó, tiểu bí.\nCHÂM CỨU\nChâm thẳng sâu 0,3 – 1,5 thốn. Cứu 10 – 45 phút.\nGIẢI PHẪU\nHuyệt ở trên đường trắng giữa bụng, giữa nền và trụ của đường trắng. Sau đường trắng là mạc ngang và phúc mạc. Vào sâu là ổ bụng dưới, có đáy bàng quang khi rỗng, đáy của tử cung khi không có thai.\nDa vùng huyệt chi phối bởi tiết đoạn thần kinh L1.\nHuyệt bên trái gọi là Bào Môn, bên phải là Tử Hộ.",
      "phoiHuyet": "Phối Phục Lưu (Th 7) + Quan Nguyên (Nh 4) Tam Âm Giao (Ty 6) + Thái Xung (C 3) + Thiên Xu (Vi 25) trị xích bạch đái (Châm Cứu Tập Thành).\n2.\tPhối Chiếu Hải (Th 6) + Lãi Câu (C 5) + Tam Âm Giao (Ty 6) + Thiếu Phủ (Tm 8) trị âm hành đột nhiên cương lên khác thường (Châm Cứu Học Thủ Sách)",
      "ghiChu": "Trước khi châm, bảo người bệnh đi tiểu để tránh châm vào bàng quang.\nBí tiểu không châm sâu.\nCó thai không châm sâu.",
      "thamKhao": "",
      "sections": [
        {
          "h": "TÊN HUYỆT",
          "body": "Huyệt ở xương (Cốt) mu, có hình dạng cong (khúc), vì vậy gọi là Khúc Cốt."
        },
        {
          "h": "TÊN KHÁC",
          "body": "Hồi Cốt, Khuất Cốt, Niệu Bao."
        },
        {
          "h": "XUẤT XỨ",
          "body": "Giáp Ất Kinh."
        },
        {
          "h": "VỊ TRÍ",
          "body": "Ở trên xương mu, dưới huyệt Trung Cực 1 thốn hoặc chỗ lõm ngay chính giữa bờ trên xương mu."
        },
        {
          "h": "ĐẶC TÍNH",
          "body": "Huyệt thứ 2 của mạch Nhâm.\nHuyệt Hội của mạch Nhâm và kinh Túc Quyết Âm Can.\nHuyệt Hội của kinh Túc Quyết Âm Can và mạch Âm Kiều.\nHuyệt Hội của các kinh cân – cơ của 3 kinh âm ở chân."
        },
        {
          "h": "CHỦ TRỊ",
          "body": "Trị bàng quang viêm, dịch hoàn viêm, tử cung sa, kinh nguyệt không đều, tiểu khó, tiểu bí."
        },
        {
          "h": "CHÂM CỨU",
          "body": "Châm thẳng sâu 0,3 – 1,5 thốn. Cứu 10 – 45 phút."
        },
        {
          "h": "GIẢI PHẪU",
          "body": "Huyệt ở trên đường trắng giữa bụng, giữa nền và trụ của đường trắng. Sau đường trắng là mạc ngang và phúc mạc. Vào sâu là ổ bụng dưới, có đáy bàng quang khi rỗng, đáy của tử cung khi không có thai.\nDa vùng huyệt chi phối bởi tiết đoạn thần kinh L1.\nHuyệt bên trái gọi là Bào Môn, bên phải là Tử Hộ."
        }
      ],
